// // This module implements a 16-bit shift register with parallel load functionality.
// On every falling edge of the clock signal (clk), the shift register value is updated.
// If the reset signal (rst) is low, indicating a reset condition, the shift register value (Q) is set to 0.
// If the load signal is low, the value of load_val is loaded into the shift register.
// Otherwise, the shift register shifts right by 1 bit, with the MSB set to 0.
module ShiftReg_16_load(
   input                clk,
   input                rst,
   input                load,
   input  [15:0]        load_val,
   output reg [15:0]    Q
);
    always@(posedge clk)begin
        if(rst) Q <= 16'd0;
        else if(load) Q <= load_val;
        else Q <= {Q[14:0], 1'b0};
    end
endmodule

